+    fn compute_tileset_hash(spec: &TilesetSpec) -> u64 {
+        let canonical = serde_json::to_vec(spec).unwrap_or_default();
+        let mut hasher = DefaultHasher::new();
+        hasher.write(&canonical);
+        hasher.finish()
+    }
